+        // Verify which connections are in the pool (FIFO)
+        let r1 = pool.acquire().await.unwrap();
+        assert_eq!(r1.conn.as_deref(), Some("a"));
+        let r2 = pool.acquire().await.unwrap();
+        assert_eq!(r2.conn.as_deref(), Some("b"));
